const settings = $('Load Global Settings').first()?.json ?? {};
const request = $('Send Member Template Email Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? {};
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const truthy = (value) => ['1', 'true', 'yes', 'y', 'on'].includes(clean(value).toLowerCase());
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const member = clean(body.member);
const membership = clean(body.membership);
const email = clean(body.email);
const templateKey = clean(body.template_key);
const renderedSubject = clean(body.rendered_subject);
const renderedMessage = clean(body.rendered_message);
const renderedSignature = clean(body.rendered_signature);
const returnUrl = clean(body.return_url) || `${n8nBaseUrl}/webhook/member-search-detail?member=${encodeURIComponent(member)}&membership=${encodeURIComponent(membership)}&email=${encodeURIComponent(email)}`;
const rawMemberId = Number.parseInt(clean(body.member_id), 10);
const deliveryMode = truthy(body.test_mode) ? 'test' : 'production';
const emailType = clean(body.email_type).toLowerCase() === 'html' ? 'html' : 'text';
const joinSeparator = emailType === 'html' ? '<br><br>' : '\n\n';
const errorMessage = !templateKey
  ? 'template_key is required'
  : !renderedSubject
    ? 'rendered_subject is required'
    : !renderedMessage
      ? 'rendered_message is required'
      : (!member && !Number.isInteger(rawMemberId) ? 'member_id or member is required' : '');
return [{ json: { member_id: Number.isInteger(rawMemberId) ? rawMemberId : null, member, membership, email, template_key: templateKey, sender_name: settings.email_sender_name || 'Steve Short', reply_to: settings.email_reply_to || 'members.avondaleltc@gmail.com', delivery_mode: deliveryMode, test_recipient: clean(settings.default_test_recipient) || 'steve.short@gmail.com', return_url: returnUrl, rendered_subject: renderedSubject, rendered_message: renderedMessage, rendered_signature: renderedSignature, final_rendered_message: [renderedMessage, renderedSignature].filter(Boolean).join(joinSeparator).trim(), email_type: emailType, n8n_base_url: n8nBaseUrl, error_message: errorMessage } }];

const input = $input.first().json ?? {};
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sqlInteger = (value) => Number.isInteger(value) ? String(value) : 'NULL';
const memberSql = sqlLiteral(input.member);
const membershipSql = sqlLiteral(input.membership);
const emailSql = sqlLiteral(input.email);
const memberIdSql = sqlInteger(input.member_id);
const sql = `
WITH base_member AS (
  SELECT rm.id AS raw_member_id, trim(concat_ws(' ', rm."First name", rm."Last name")) AS member_name, rm."First name" AS first_name, rm."Last name" AS last_name, NULLIF(trim(rm."Email address"), '') AS member_email, NULLIF(trim(rm."Venue ID"), '') AS venue_id, rm."Membership" AS membership, NULLIF(trim(rm."Status"), '') AS member_status, NULLIF(trim(rm."Payment"), '') AS payment_status, NULLIF(trim(rm."Start Date"), '') AS start_date, NULLIF(trim(rm."Expiry Date"), '') AS expiry_date, rm."Paid" AS paid_total, NULLIF(trim(rm."Address 1"), '') AS address_1, NULLIF(trim(rm."Postcode"), '') AS postcode
  FROM public.raw_members rm
  WHERE COALESCE(rm.is_current, true) = true
    AND ((${memberIdSql} IS NOT NULL AND rm.id = ${memberIdSql}) OR (${memberIdSql} IS NULL AND trim(concat_ws(' ', rm."First name", rm."Last name")) = ${memberSql} AND (${membershipSql} = '' OR rm."Membership" = ${membershipSql}) AND (${emailSql} = '' OR public.normalize_match_email(rm."Email address") = public.normalize_match_email(${emailSql}))))
  ORDER BY CASE WHEN (${membershipSql} <> '' AND rm."Membership" = ${membershipSql}) THEN 0 ELSE 1 END, rm.id
  LIMIT 1
), member_identity AS (
  SELECT COALESCE((SELECT raw_member_id FROM base_member), ${memberIdSql}) AS raw_member_id, COALESCE((SELECT member_name FROM base_member), ${memberSql}) AS member_name, COALESCE((SELECT first_name FROM base_member), split_part(${memberSql}, ' ', 1)) AS first_name, COALESCE((SELECT last_name FROM base_member), NULLIF(regexp_replace(${memberSql}, '^\\S+\\s*', ''), '')) AS last_name, COALESCE((SELECT member_email FROM base_member), NULLIF(${emailSql}, '')) AS member_email, COALESCE((SELECT membership FROM base_member), NULLIF(${membershipSql}, '')) AS membership, COALESCE((SELECT member_status FROM base_member), NULL) AS member_status, COALESCE((SELECT payment_status FROM base_member), NULL) AS payment_status, COALESCE((SELECT start_date FROM base_member), NULL) AS start_date, COALESCE((SELECT expiry_date FROM base_member), NULL) AS expiry_date, COALESCE((SELECT paid_total FROM base_member), NULL::numeric) AS paid_total, COALESCE((SELECT address_1 FROM base_member), NULL) AS address_1, COALESCE((SELECT postcode FROM base_member), NULL) AS postcode
), best_contact AS (
  SELECT bc.*
  FROM member_identity mi
  LEFT JOIN LATERAL public.resolve_best_contact_row(mi.member_name, COALESCE(NULLIF(${emailSql}, ''), mi.member_email), NULLIF(regexp_replace(mi.member_name, '^\\S+\\s*', ''), ''), EXISTS (SELECT 1 FROM public.raw_members rmf WHERE COALESCE(rmf.is_current, true) = true AND trim(concat_ws(' ', rmf."First name", rmf."Last name")) = mi.member_name AND rmf."Membership" ILIKE '%Family%')) bc ON TRUE
), main_contact_candidates AS (
  SELECT trim(concat_ws(' ', mc."First name", mc."Last name")) AS main_contact_name, NULLIF(trim(mc."Email address"), '') AS main_contact_email, NULLIF(trim(mc."Address 1"), '') AS main_contact_address_1, NULLIF(trim(mc."Town"), '') AS main_contact_town, NULLIF(trim(mc."Postcode"), '') AS main_contact_postcode, row_number() OVER (ORDER BY CASE WHEN NULLIF(trim(mc."Email address"), '') IS NOT NULL THEN 0 ELSE 1 END, CASE WHEN mi.last_name IS NOT NULL AND public.normalize_match_text(mc."Last name") = public.normalize_match_text(mi.last_name) THEN 0 ELSE 1 END, CASE WHEN mi.postcode IS NOT NULL AND public.normalize_match_text(mc."Postcode") = public.normalize_match_text(mi.postcode) THEN 0 ELSE 1 END, mc.id DESC) AS candidate_rank
  FROM member_identity mi
  JOIN public.vw_raw_members_main_contacts_current mc
    ON trim(concat_ws(' ', mc."First name", mc."Last name")) <> mi.member_name
   AND COALESCE(mc."Membership", '') = COALESCE(mi.membership, '')
   AND COALESCE(mc."Status", '') = COALESCE(mi.member_status, '')
   AND COALESCE(mc."Payment", '') = COALESCE(mi.payment_status, '')
   AND COALESCE(mc."Start Date", '') = COALESCE(mi.start_date, '')
   AND COALESCE(mc."Expiry Date", '') = COALESCE(mi.expiry_date, '')
   AND COALESCE(mc."Paid", -1::numeric) = COALESCE(mi.paid_total, -1::numeric)
   AND ((mi.last_name IS NOT NULL AND public.normalize_match_text(mc."Last name") = public.normalize_match_text(mi.last_name)) OR (mi.postcode IS NOT NULL AND public.normalize_match_text(mc."Postcode") = public.normalize_match_text(mi.postcode)) OR (mi.address_1 IS NOT NULL AND public.normalize_match_text(mc."Address 1") = public.normalize_match_text(mi.address_1)))
), main_contact AS (
  SELECT COALESCE(NULLIF(TRIM(bcm.email_address), ''), mcc.main_contact_email) AS email_address, COALESCE(NULLIF(TRIM(bcm.address_1), ''), mcc.main_contact_address_1) AS address_1, COALESCE(NULLIF(TRIM(bcm.town), ''), mcc.main_contact_town) AS town, COALESCE(NULLIF(TRIM(bcm.postcode), ''), mcc.main_contact_postcode) AS postcode, mcc.main_contact_name
  FROM main_contact_candidates mcc
  LEFT JOIN LATERAL public.resolve_best_contact_row(mcc.main_contact_name, mcc.main_contact_email, NULLIF(regexp_replace(mcc.main_contact_name, '^\\S+\\s*', ''), ''), false) bcm ON TRUE
  WHERE mcc.candidate_rank = 1
)
SELECT mi.member_name, mi.first_name, mi.last_name, mi.membership, COALESCE(NULLIF(${emailSql}, ''), NULLIF(TRIM(mc.email_address), ''), NULLIF(TRIM(bc.email_address), ''), NULLIF(TRIM(mi.member_email), '')) AS to_email, CASE WHEN COALESCE(mi.member_name, '') = '' THEN 'Member is required' WHEN COALESCE(COALESCE(NULLIF(${emailSql}, ''), NULLIF(TRIM(mc.email_address), ''), NULLIF(TRIM(bc.email_address), ''), NULLIF(TRIM(mi.member_email), '')), '') = '' THEN 'No email address found for ' || mi.member_name ELSE NULL END AS error_message FROM member_identity mi LEFT JOIN best_contact bc ON TRUE LEFT JOIN main_contact mc ON TRUE;`;
return [{ json: { ...input, sql } }];

const input = $('Resolve Send Request').first().json ?? {};
const errorRow = $('Load Send Context').first()?.json ?? {};
const message = errorRow.error_message || input.error_message || 'Unable to send email.';
const returnUrl = input.return_url || '#';
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Email Not Sent</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 10px;font-size:30px}p{color:#6b7785;line-height:1.5}.message{margin:18px 0;padding:14px 16px;border-radius:14px;background:#fdecec;color:#b93a3a;font-weight:700}.actions{margin-top:22px;display:flex;gap:12px;flex-wrap:wrap}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Email Not Sent</h1><p>The member-detail email panel could not complete this request.</p><div class="message">${escapeHtml(message)}</div><div class="actions"><a class="button" href="${escapeHtml(returnUrl)}">Back to Member Detail</a></div></div></body></html>`;
return [{ json: { html } }];

const input = $('Resolve Send Request').first().json ?? {};
const context = $('Load Send Context').first()?.json ?? {};
const intendedRecipient = context.to_email;
const actualRecipient = input.delivery_mode === 'production' ? intendedRecipient : input.test_recipient;
return [{ json: { sender_name: input.sender_name, reply_to: input.reply_to, template_key: input.template_key, intended_recipient: intendedRecipient, actual_recipient: actualRecipient, delivery_mode: input.delivery_mode, member: context.member_name, membership: context.membership, return_url: input.return_url, rendered_subject: input.rendered_subject, rendered_message: input.final_rendered_message, email_type: input.email_type } }];

const item = $('Build Send Payload').first().json ?? {};
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const modeLabel = item.delivery_mode === 'production' ? 'Production' : 'Test';
const recipientSummary = item.delivery_mode === 'production' ? escapeHtml(item.actual_recipient) : `${escapeHtml(item.actual_recipient)} (intended recipient: ${escapeHtml(item.intended_recipient)})`;
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Email Sent</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}h1{margin:0 0 10px;font-size:30px}p{color:#6b7785;line-height:1.5}.pill{display:inline-flex;align-items:center;padding:8px 12px;border-radius:999px;background:#edf8f2;color:#1f7a4d;font-weight:700;margin:12px 0 18px}dl{display:grid;grid-template-columns:max-content 1fr;gap:10px 16px;margin:0}dt{font-weight:700}dd{margin:0;color:#2e3d4e}.actions{margin-top:22px;display:flex;gap:12px;flex-wrap:wrap}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Email Sent</h1><p>The edited member-detail email has been sent.</p><div class="pill">${escapeHtml(modeLabel)} mode</div><dl><dt>Member</dt><dd>${escapeHtml(item.member)}</dd><dt>Membership</dt><dd>${escapeHtml(item.membership || 'Not available')}</dd><dt>Template</dt><dd>${escapeHtml(item.template_key)}</dd><dt>Recipient</dt><dd>${recipientSummary}</dd><dt>Subject</dt><dd>${escapeHtml(item.rendered_subject)}</dd></dl><div class="actions"><a class="button" href="${escapeHtml(item.return_url || '#')}">Back to Member Detail</a></div></div></body></html>`;
return [{ json: { html } }];
